#include<bits/stdc++.h>
using namespace std;
int n;
int pre[200010],in[200010],posp[200010],posi[200010];
int l[200010],r[200010];
int dfs(int pl,int pr,int il,int ir)
{
    if(pl>pr||il>ir)
    {
        return 0;
    }
    int pos=posi[pre[pl]],tmp=pre[pl];
    if(pos<il||pos>ir)
    {
        printf("-1");
        exit(0);
    }
    if(pl==pr||il==ir)
    {
        return tmp;
    }
    int siz=pos-il;
    l[tmp]=dfs(pl+1,pl+siz,il,pos-1);
    r[tmp]=dfs(pl+siz+1,pr,pos+1,ir);
    return tmp;
}
int main()
{
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&pre[i]);
        posp[pre[i]]=i;
    }
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&in[i]);
        posi[in[i]]=i;
    }
    if(pre[1]!=1)
    {
        printf("-1");
        return 0;
    }
    dfs(1,n,1,n);
    for(int i=1;i<=n;i++)
    {
        printf("%d %d\n",l[i],r[i]);
    }
    return 0;
}
